import { moduleMetadata } from '@storybook/angular';
import { PfNotificationComponent } from './notification.component';
const meta = {
    title: 'Composants/Notification',
    component: PfNotificationComponent,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Bandeau d'information système plein-largeur. Persiste jusqu'à fermeture explicite (différent de Toast qui est éphémère).",
            },
        },
        layout: 'fullscreen',
    },
    decorators: [moduleMetadata({ imports: [PfNotificationComponent] })],
    argTypes: {
        variant: { control: 'inline-radio', options: ['info', 'success', 'warning', 'danger'] },
        dismissible: { control: 'boolean' },
    },
    args: { variant: 'info', dismissible: true },
    render: (args) => ({
        props: args,
        template: `
      <pf-notification
        [variant]="variant"
        [dismissible]="dismissible"
        [actionLabel]="actionLabel || ''"
        [actionHref]="actionHref || ''"
      >Maintenance programmée demain de 22h à 23h.</pf-notification>
    `,
    }),
};
export default meta;
export const Default = {};
export const WithAction = {
    args: {
        variant: 'warning',
        dismissible: true,
        actionLabel: 'Compléter mon profil',
        actionHref: '/profil',
    },
    render: (args) => ({
        props: args,
        template: `
      <pf-notification
        [variant]="variant"
        [dismissible]="dismissible"
        [actionLabel]="actionLabel"
        [actionHref]="actionHref"
      >Votre profil n'est pas complet.</pf-notification>
    `,
    }),
};
export const Variants = {
    render: () => ({
        template: `
      <div style="display: flex; flex-direction: column; gap: 8px;">
        <pf-notification variant="info">Le service sera indisponible dimanche entre 2h et 4h.</pf-notification>
        <pf-notification variant="success">Votre dossier a été transmis avec succès.</pf-notification>
        <pf-notification variant="warning" actionLabel="En savoir plus" actionHref="/cookies">
          Cette page utilise des cookies pour améliorer votre expérience.
        </pf-notification>
        <pf-notification variant="danger" [dismissible]="true">
          Une panne réseau affecte actuellement le service.
        </pf-notification>
      </div>
    `,
    }),
};
export const NonDismissible = {
    args: { variant: 'danger', dismissible: false },
    render: (args) => ({
        props: args,
        template: `
      <pf-notification [variant]="variant" [dismissible]="dismissible">
        Ce message persiste tant que la situation est active.
      </pf-notification>
    `,
    }),
};
